import React, { useState } from 'react';
import styled from 'styled-components';
import { motion, AnimatePresence } from 'framer-motion';

const ChatbotContainer = styled.div`
  position: fixed;
  bottom: 20px;
  right: 20px;
  z-index: 1000;
`;

const ChatbotToggle = styled(motion.button)`
  width: 55px;
  height: 55px;
  border-radius: 50%;
  background: ${props => props.theme.colors.accentPrimary};
  border: none;
  color: #000;
  font-size: 1.4rem;
  cursor: pointer;
  box-shadow: ${props => props.theme.shadows.glow};
  display: flex;
  align-items: center;
  justify-content: center;
  transition: ${props => props.theme.transitions.default};

  &:hover {
    transform: scale(1.1) rotate(5deg);
  }
`;

const ChatWindow = styled(motion.div)`
  position: absolute;
  bottom: 70px;
  right: 0;
  width: 380px;
  height: 550px;
  background: rgba(13, 13, 13, 0.95);
  border-radius: ${props => props.theme.borderRadius.large};
  box-shadow: ${props => props.theme.shadows.card};
  display: flex;
  flex-direction: column;
  border: 1px solid ${props => props.theme.colors.border};
  backdrop-filter: blur(25px);
  overflow: hidden;
`;

const ChatHeader = styled.div`
  background: ${props => props.theme.colors.secondaryBackground};
  padding: 1.2rem 1.5rem;
  color: ${props => props.theme.colors.textPrimary};
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-bottom: 1px solid ${props => props.theme.colors.border};
`;

const ChatTitle = styled.h3`
  margin: 0;
  font-size: 1rem;
  font-weight: 700;
  letter-spacing: 0.5px;
  text-transform: uppercase;
  background: ${props => props.theme.colors.accentPrimary};
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
`;

const MessageList = styled.div`
  flex: 1;
  overflow-y: auto;
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;

  &::-webkit-scrollbar {
    width: 4px;
  }

  &::-webkit-scrollbar-track {
    background: transparent;
  }

  &::-webkit-scrollbar-thumb {
    background: ${props => props.theme.colors.border};
    border-radius: 10px;
  }
`;

const Message = styled(motion.div)<{ isBot: boolean }>`
  display: flex;
  justify-content: ${props => props.isBot ? 'flex-start' : 'flex-end'};
  margin-bottom: 0.5rem;
`;

const MessageBubble = styled.div<{ isBot: boolean }>`
  max-width: 85%;
  padding: 0.8rem 1.2rem;
  border-radius: ${props => props.theme.borderRadius.medium};
  background: ${props => props.isBot ? props.theme.colors.secondaryBackground : props.theme.colors.accentPrimary};
  color: ${props => props.isBot ? props.theme.colors.textPrimary : '#000'};
  font-size: 0.95rem;
  line-height: 1.5;
  border: 1px solid ${props => props.isBot ? props.theme.colors.border : 'transparent'};
  box-shadow: ${props => !props.isBot ? props.theme.shadows.glow : 'none'};
`;

const InputContainer = styled.form`
  padding: 1.2rem;
  background: ${props => props.theme.colors.secondaryBackground};
  display: flex;
  gap: 0.8rem;
  border-top: 1px solid ${props => props.theme.colors.border};
`;

const Input = styled.input`
  flex: 1;
  background: ${props => props.theme.colors.background};
  border: 1px solid ${props => props.theme.colors.border};
  border-radius: ${props => props.theme.borderRadius.medium};
  padding: 0.7rem 1rem;
  color: ${props => props.theme.colors.textPrimary};
  font-size: 0.9rem;
  transition: ${props => props.theme.transitions.default};

  &:focus {
    outline: none;
    border-color: #4facfe;
    background: rgba(255, 255, 255, 0.05);
  }
`;

const SendButton = styled.button`
  background: ${props => props.theme.colors.accentPrimary};
  border: none;
  width: 40px;
  height: 40px;
  border-radius: 50%;
  color: #000;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: ${props => props.theme.transitions.default};

  &:hover {
    transform: scale(1.05);
    box-shadow: ${props => props.theme.shadows.glow};
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
  }
`;

interface ChatMessage {
  id: string;
  text: string;
  isBot: boolean;
  timestamp: Date;
}

const FAQs = [
  {
    keywords: ['hello', 'hi', 'hey', 'start'],
    response: 'Hello! 👋 I\'m Plutus Assistant. I can help you manage your wealth and understand market trends. Try asking me about:\n• Portfolio management\n• Market sectors\n• Analytics and graphs\n• Precious metals (Gold/Silver)\n• Financial news'
  },
  {
    keywords: ['portfolio', 'add stock', 'how to add'],
    response: '📈 Managing Your Portfolio:\n1. Browse "📈 Stocks" in the sidebar\n2. Select a market sector (e.g., IT, Banking)\n3. Click the "Add" button on any stock card\n4. View your investments in the "💼 Portfolio" page\n\nYou can also remove stocks using the ✕ icon.'
  },
  {
    keywords: ['pe ratio', 'graph', 'chart', 'valuation'],
    response: '📊 Understanding P/E Ratio:\n• Price-to-Earnings (P/E) shows how much investors pay for $1 of earnings.\n• We track the 12-month progression in your portfolio.\n• A lower P/E relative to peers might indicate an undervalued stock.\n• Look for the green trend line in your stock analytics.'
  },
  {
    keywords: ['k-means', 'clustering', 'cluster', 'group'],
    response: '🎯 Advanced Clustering:\n• We use AI-driven K-Means to group stocks by volatility and performance.\n• 🟢 Green (Growth): Change > 5%\n• 🟡 Yellow (Stable): Change -2% to 5%\n• 🔴 Red (Declining): Change < -2%\n\nThis helps you diversify and identify risk levels across your portfolio.'
  },
  {
    keywords: ['news', 'financial news', 'market news', 'updates'],
    response: '📰 Market Insights:\n• Our News page aggregates real-time updates from top financial sources.\n• Filter by "Economy", "Markets", or "Education" to find what matters.\n• Use the search bar to find news about specific companies.'
  },
  {
    keywords: ['gold', 'silver', 'metals', 'precious', 'commodity'],
    response: '💰 Precious Metals:\n• We fetch live spot prices for Gold and Silver directly from Yahoo Finance.\n• You can track 12-month trends and correlation between metals.\n• Gold is often a hedge against inflation, while Silver has industrial demand.'
  },
  {
    keywords: ['search', 'find', 'navigate', 'how do i'],
    response: '🔍 Navigation Guide:\n• "📰 News": Latest market updates\n• "💰 Gold/Silver": Real-time commodity tracking\n• "📈 Stocks": Browse market sectors\n• "💼 Portfolio": Manage your own investments (Login required)'
  },
  {
    keywords: ['prediction', 'future', 'price prediction'],
    response: '🔮 Price Prediction:\n• We use statistical models to estimate future price movements.\n• These are for educational purposes and not financial advice.\n• Predictions are based on historical volatility and recent trends.'
  }
];

const Chatbot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: '1',
      text: 'Hello! 👋 I\'m your Plutus Assistant. How can I help you today?',
      isBot: true,
      timestamp: new Date()
    }
  ]);
  const [inputValue, setInputValue] = useState('');

  const findResponse = (userMessage: string): string => {
    const lowerMessage = userMessage.toLowerCase().trim();

    for (const faq of FAQs) {
      if (faq.keywords.some(keyword => lowerMessage.includes(keyword))) {
        return faq.response;
      }
    }

    return "Sorry, I didn't quite understand that. Try asking me about:\n• Portfolio management\n• Stock sectors\n• Charts and graphs\n• Gold/Silver prices\n• News features\n• How to use the app";
  };

  const handleSendMessage = () => {
    if (!inputValue.trim()) return;

    // Add user message
    const userMessage: ChatMessage = {
      id: String(messages.length + 1),
      text: inputValue,
      isBot: false,
      timestamp: new Date()
    };

    setMessages([...messages, userMessage]);
    setInputValue('');

    // Simulate bot response delay
    setTimeout(() => {
      const response = findResponse(inputValue);
      const botMessage: ChatMessage = {
        id: String(messages.length + 2),
        text: response,
        isBot: true,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMessage]);
    }, 500);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    handleSendMessage();
  };

  return (
    <ChatbotContainer>
      <ChatbotToggle
        onClick={() => setIsOpen(!isOpen)}
        animate={{ scale: isOpen ? 0.9 : 1 }}
        title="Chat Assistant"
      >
        {isOpen ? '✕' : '💬'}
      </ChatbotToggle>

      <AnimatePresence mode="wait">
        {isOpen && (
          <ChatWindow
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ type: 'spring', damping: 25, stiffness: 300 }}
          >
            <ChatHeader>
              <ChatTitle>Assistant</ChatTitle>
              <div style={{ opacity: 0.6, fontSize: '0.8rem' }}>Online</div>
            </ChatHeader>

            <MessageList>
              {messages.map((message) => (
                <Message
                  key={message.id}
                  isBot={message.isBot}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                >
                  <MessageBubble isBot={message.isBot}>
                    {message.text.split('\n').map((line, i) => (
                      <div key={i}>{line}</div>
                    ))}
                  </MessageBubble>
                </Message>
              ))}
            </MessageList>

            <InputContainer onSubmit={handleSubmit}>
              <Input
                type="text"
                placeholder="Type a message..."
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
              />
              <SendButton type="submit" disabled={!inputValue.trim()}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <line x1="22" y1="2" x2="11" y2="13"></line>
                  <polygon points="22 2 15 22 11 13 2 9 22 2"></polygon>
                </svg>
              </SendButton>
            </InputContainer>
          </ChatWindow>
        )}
      </AnimatePresence>
    </ChatbotContainer>
  );
};

export default Chatbot;
